Type Maillon = Enregistrement
Debut
    idx  : Entier;
    suiv : ^Maillon;
Fin;

Type FileIdx = Enregistrement
Debut
    tete  : ^Maillon;
    queue : ^Maillon;
Fin;

Procedure Init(Var F : FileIdx)
Debut
    F.tete := NIL;
    F.queue := NIL;
Fin;

Procedure Enfiler(Var F : FileIdx, i : Entier)
Var n : ^Maillon;
Debut
    n := allouer(taille(Maillon));
    n->idx := i;
    n->suiv := NIL;
    Si F.tete = NIL Alors
        F.tete := n; F.queue := n;
    Sinon
        F.queue->suiv := n; F.queue := n;
    FinSi
Fin;

Procedure Defiler(Var F : FileIdx, Var i : Entier)
Var t : ^Maillon;
Debut
    t := F.tete;
    i := t->idx;
    F.tete := t->suiv;
    Si F.tete = NIL Alors F.queue := NIL; FinSi
    liberer(t);
Fin;

Fonction EstVide(F : FileIdx) : Booleen
Debut
    Retourner(F.tete = NIL);
Fin;

Fonction Premier(F : FileIdx) : Entier
Debut
    Retourner(F.tete->idx);
Fin;

